#include <bits/stdc++.h>
using namespace std;
int n,m,t,a[102],b[102],dp[102][202][202];
int main(){
    scanf("%d%d%d",&n,&m,&t);
    for(int i=1;i<=n;i++)
        scanf("%d%d",&a[i],&b[i]);
    for(int i=1;i<=n;i++)
        for(int j=1;j<=m;j++)
            for(int k=1;k<=t;k++)
                if(a[i]<=j && b[i]<=k)
                    dp[i][j][k]=max(dp[i-1][j][k],dp[i-1][j-a[i]][k-b[i]]+1);
                else
                    dp[i][j][k]=dp[i-1][j][k];
    printf("%d",dp[n][m][t]);
    return 0;
}
